VALUES
  ('cpa-moex-01585', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '國際財務報導準則有關營運部門資訊之揭露，下列敘述何者錯誤？', '["公司總部可能未賺得收入，故非屬營運部門", "公司某些功能性部門可能賺得之收入僅為企業活動偶發之收入，故非屬營運部門", "兩個部門若有相似的研發項目，則可以彙總為同一部門", "主要營運決策者只要其職能涉及分配資源予企業營運部門並評量其績效，不必然為有特定職稱之 經理人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01586', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '國際會計準則有關期中財務報表認列及衡量原則，下列敘述何者錯誤？', '["每一期中期間所認列之所得稅費用，應依整個財務年度所估計之年度平均有效所得稅率計算認列", "預期於年底發生的定期維修成本，對期中報導目的而言，雖然編製期中財務報導時尚未發生，公 司仍須預先認列費用", "公司本年度每季預計投入研發費用一萬元。雖然公司預計到第三季結束時，前三季研發費用將可 以符合資產資本化條件，但公司不應該在編製第一季期中報表時將一萬元資本化", "期中期間之退休金成本應採用前一財務年度結束日依精算決定之退休金成本率，以年初至當期末 為基礎計算，並針對該結束日後之重大市場波動，及重大縮減、清償或其他重大一次性事項加以 調整"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01587', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '日支付完債息後發生財務困難，經協議將本金降低為$70,000，利息為每年 $3,000，惟X5年年底若藍天企業財務狀況改善，則本金恢復為$100,000，以後 利息恢復為每年$6,000。民安人壽評估該債券未來無法依合約收回所有利息與 本金。預期該公司債可收回之本金為$70,000，預期剩餘期間之票面利息為每年 收回$3,000，該公司債X3年底攤銷後成本為$103,546。X5年12月31日支付完債 息後因藍天企業財務狀況改善，經協議藍天企業有能力以原發行條件予以清償。 試作金融資產減損及減損迴轉相關會計分錄。（10分）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01588', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '企業財務報表通常基於繼續經營假設編製，以下有關繼續經營假設之敘述，何者錯誤？', '["當企業繼續經營之能力有重大疑慮時，應予以揭露", "企業應以所有可得之資訊，並依個案事實判斷，評估資產負債表日後至少12個月內能否繼續經營", "當一企業擁有經營獲利之歷史且可隨時獲得財務資源，不須詳細分析，即可推論其採繼續經營假 設尚屬適當", "如企業意圖或必須解散清算者，應以現金基礎編製財務報表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01589', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '對勞務提供的交易而言，下列說明何者錯誤？ 完 工 百 分 比 法                           成 本 回 收 法', '["適用於交易結果無法可靠估計之情況  適用於交易結果能夠可靠估計之情況", "收入應於勞務提供期間內認列  僅在已認列費用的可回收範圍內認列收入", "估計總成本如有變動應作為會計估計變動  已發生的成本應於當期認列為費用", "帳款若無法收現應認列為壞帳  不可認列超過成本以外的收入，但全部勞務提供 完成時除外"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01590', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於X1年11月1日出售一台機器給乙公司，該機器帳列成本$720,000，現金價為$929,736。乙 公司於交易日當天支付現金$80,000，餘款開立24張票據，自X1年12月1日起每月月初付$40,000。 該票據之隱含利率為月息1%。試問甲公司X1年度因本筆銷貨需認列之總利益為何？', '["$320,000", "$218,232", "$226,415", "$214,332"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01591', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '曉生企業X1年度之壞帳費用$250,000，出售土地利益$456,000，廠房徵收之利益$380,000，稅率 25%，應付所得稅減少$72,000，本期淨利$2,000,000。曉生企業X1年度營業活動之淨現金流量為 何？', '["$1,581,000", "$1,486,000", "$1,437,000", "$1,342,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01592', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '有關勞務提供交易認列為收入的敘述，下列何者錯誤？', '["安裝費應依安裝完成程度認列收入，除非該安裝係屬銷售商品附加之條件，此時應於商品銷售時 認列", "企業發展客制化軟體收費，應按發展之完成程度認列收入", "學費收入應於教學或講授期間認列收入", "入場費若以套票方式出售，其入場費收入應於活動發生時認列"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01593', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '有關固定價格售後購回合約（sales and repurchase agreements）的會計觀念及處理之敘述，下列何者 錯誤？', '["該合約在法律形式上應視為銷貨（因為合約早已簽訂），但經濟實質上應視為借款融資負債", "根據實質重於形式原則，該合約的產品所有權雖已移轉，但事實上它是一種存貨擔保借款觀念， 而非真正的銷貨", "此種合約是一種有借款之實，但無借款之名的融資安排，俗稱為「資產負債表外融資」", "賣方應將售價與再買回價格的差額，在出售與再買回期間內攤銷為利息收入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01594', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '布朗公司於X2年1月1日為了興建廠房取得土地（含建物）。布朗公司相關支出包含：土地售價 250萬元，仲介費用18萬元，法律過戶相關費用12萬元。已知該土地原始建物帳面價值為50萬元。 布朗公司取得該土地後，花了27萬元移除該建物。布朗公司於X2年1月1日起與一建築公司簽訂 合約興建該廠房，工程成本為1500萬元，預計X3年5月1日完工。與此廠房有關的借貸合約利率為 5%，試問X2年12月31日止，土地帳面價值為何？', '["280萬元", "307萬元", "294萬元", "322萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01595', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司在X1年12月31日帳上建築物原始成本為400萬元，累計折舊為150萬元，其剩餘的使用 年限為5年，且該建築物到期日將無殘值。甲公司於X2年1月1日決定從成本模式轉為重估價模式 作為續後評價，假設該建築物當日之公允價值為450萬元，且甲公司決定在重估價日依資產帳面 金額之變動，按比例重新計算累計折舊。則甲公司X2年1月1日重估價後，該建築物帳上之累計折 舊金額為何？', '["270萬元", "250萬元", "150萬元", "0元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01596', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '若客觀證據顯示某一放款已經發生減損，若原始有效利率為5%、市場利率為6%、台銀一年期定存 利率2%、顧客要求協商利率3.5%，則計算減損金額時，應該以那一個利率折現？', '["2%", "3.5%", "5%", "6%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01597', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列有關無形資產會計處理之敘述何者錯誤？', '["內部產生之商譽不得認列為資產", "被收購公司進行中之研究發展專案計畫不得列為無形資產", "無形項目已認列為費用者，不得轉列為無形資產", "非確定耐用年限之無形資產不得攤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01598', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '禮聯公司有一土地於X1年12月31日成本為700萬元。當時依照國際會計準則36號減損測試，認 列100萬元減損。禮聯公司在X2年4月1日依照國際會計準則第5號規定，將該土地分類為待出售 資產，當日之公允價值減出售成本的金額為550萬元。截至X2年12月31日禮聯公司仍未出售該資 產，但當天的公允價值減出售成本的金額因為房地產市場的復甦已經回升至 800 萬元。假設禮聯公 司於X3年2月1日將此建築物以850萬元出售。則禮聯公司在X3年2月1日認列之出售利益金額 為何？', '["150萬元", "50萬元", "250萬元", "300萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01599', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列那些資產應該列為投資性不動產？', '["代第三人建造之不動產", "以融資租賃出租之不動產", "於正常營業情況供出售而正在進行開發之不動產", "目前尚未決定未來用途所持有的土地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01600', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲牧場於 X2年 9月 2日購進 20頭小乳牛，待成齡後可以生產牛乳出售，每頭小乳牛購進價格 $25,000，另支付運費與檢疫費用合計$12,000，若將這20頭小乳牛立刻出售，將須支付出售成本 $6,000。則甲牧場X2年9月2日應認列「生物資產當期公允價值減出售成本之變動之利益」金額為：', '["損失$6,000", "利益$6,000", "損失$18,000", "利益$18,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
